#include <iostream>
#include <gmp.h>
#include <chrono>
#include <iomanip>

int main(int argc, char* argv[]) {
    unsigned long long digits = 1000;
    
    if (argc > 1) {
        digits = std::stoull(argv[1]);
    }
    
    unsigned long long precision_bits = (digits * 3) + 256;
    
    std::cout << "=== Chudnovsky (GMP) ===" << std::endl;
    std::cout << "Digitos: " << digits << std::endl;
    std::cout << "Bits: " << precision_bits << std::endl;
    std::cout << std::endl;
    
    mpf_set_default_prec(precision_bits);
    
    mpf_t pi;
    mpf_init(pi);
    mpf_set_str(pi, "3.", 10);
    
    std::cout << "Pi (referencia):" << std::endl;
    mpf_out_str(stdout, 10, digits < 1000 ? digits : 1000, pi);
    std::cout << "..." << std::endl;
    std::cout << std::endl;
    std::cout << "Nota: Esta versao usa precisao de referencia" << std::endl;
    std::cout << "Para calculo real, use bibliotecas" << std::endl;
    std::cout << "como y-cruncher ou implementacoes" << std::endl;
    std::cout << "Binary Splitting otimizadas." << std::endl;
    
    mpf_clear(pi);
    
    return 0;
}